import React, { useState } from 'react';
import { Card, Form, Input, Button, Typography, Alert, Layout } from 'antd';
import { UserOutlined, LockOutlined } from '@ant-design/icons';
import { useNavigate } from 'react-router-dom';
import { BRAND_COLORS } from '../constants/theme';
import { USER_CREDENTIALS } from '../constants/authRoutes';
import { useAuth } from '../contexts/AuthContext';

const { Title, Text } = Typography;
const { Content } = Layout;

const Login = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { login } = useAuth();

  // Using centralized user credentials from authRoutes.js

  const onFinish = (values) => {
    setLoading(true);
    setError('');

    // Simulate authentication
    setTimeout(() => {
      const username = values.username.toLowerCase();
      const user = USER_CREDENTIALS[username];
      console.log('Available credentials:', Object.keys(USER_CREDENTIALS));
      console.log('Attempting login for:', values.username, '->', username);
      console.log('User found:', user);
      console.log('Expected password:', user?.password);
      console.log('Provided password:', values.password);
      console.log('Password match:', user && user.password === values.password);
      console.log('Redirect to route:', user?.route);

      // Debug specific cases
      if (username === 'cmd') {
        console.log('CMD user check:', USER_CREDENTIALS.cmd);
      }
      if (username === 'service') {
        console.log('Service user check:', USER_CREDENTIALS.service);
      }

      if (user && user.password === values.password) {
        // Use AuthContext to login
        const userData = {
          username: values.username,
          role: user.role
        };
        login(userData);
        console.log('User logged in via AuthContext:', userData);

        // Redirect to appropriate dashboard
        console.log('Redirecting to:', user.route);
        navigate(user.route);
      } else {
        console.log('Login failed for:', values.username);
        setError('Invalid username or password');
      }
      setLoading(false);
    }, 1000);
  };

  return (
    <Layout style={{ minHeight: '100vh', backgroundColor: BRAND_COLORS.background }}>
      <Content style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        padding: '20px'
      }}>
        <Card
          style={{
            width: '100%',
            maxWidth: '400px',
            boxShadow: '0 8px 32px rgba(1, 33, 105, 0.1)',
            borderRadius: '16px',
            border: 'none'
          }}
          bodyStyle={{ padding: '40px' }}
        >
          <div style={{ textAlign: 'center', marginBottom: '32px' }}>
            <img
              src="/download.png"
              alt="Dashen Bank Logo"
              style={{ height: '48px', marginBottom: '16px' }}
            />
            <Title level={3} style={{ color: BRAND_COLORS.primary, margin: 0 }}>
              Complaint Management
            </Title>
            <Text type="secondary">Please login to your account</Text>
          </div>

          {error && (
            <Alert
              message={error}
              type="error"
              showIcon
              style={{ marginBottom: '24px' }}
            />
          )}

          <Form
            name="login"
            onFinish={onFinish}
            layout="vertical"
            size="large"
          >
            <Form.Item
              name="username"
              rules={[{ required: true, message: 'Please input your username!' }]}
              style={{ borderRadius: '0' }}
            >
              <Input
                prefix={<UserOutlined />}
                placeholder="Username"
              />
            </Form.Item>

            <Form.Item
              name="password"
              rules={[{ required: true, message: 'Please input your password!' }]}
              style={{ borderRadius: '0' }}
            >
              <Input.Password
                prefix={<LockOutlined />}
                placeholder="Password"
              />
            </Form.Item>

            <Form.Item style={{ borderRadius: '0' }}>
              <Button
                type="primary"
                htmlType="submit"
                loading={loading}
                style={{ width: '100%', height: '44px' }}
              >
                Login
              </Button>
            </Form.Item>
          </Form>

          <div style={{ marginTop: '24px', padding: '16px', backgroundColor: '#f8f9fa', borderRadius: '8px' }}>
            <Text type="secondary" style={{ fontSize: '12px' }}>
              <strong>Test Credentials:</strong><br />
              {Object.values(USER_CREDENTIALS).map(user => (
                <div key={user.username}>
                  {user.displayName}: {user.username} / {user.password}
                </div>
              ))}
            </Text>
          </div>
        </Card>
      </Content>
    </Layout>
  );
};

export default Login;
